--
-- The source of truth is the Lua-hosted schema-as-data modules under
-- lua/lalin/schema/.  This facade intentionally defines the clean Lalin*
-- namespace, not historical Lalin* modules.

local Schema = require("lalin.schema")

local M = {}

function M.schema(T)
    return Schema.schema(T)
end

function M.Define(T)
    return Schema.Define(T)
